// ============================================
let currentNameIndex = 0;
let studiedNames = JSON.parse(localStorage.getItem('studiedNames')) || [];

// ============================================
// 9. ФУНКЦИИ ДЛЯ 99 ИМЁН
// ============================================

function loadName(index) {
    const name = fullNamesList[index];
    if (!name) return;

    document.getElementById('slideNumber').textContent = `#${name.number}`;
    document.getElementById('slideArabic').textContent = name.arabic;
    document.getElementById('slideTransliteration').textContent = name.transliteration;
    document.getElementById('slideTranslation').textContent = name.translation;
    document.getElementById('slideMeaning').textContent = name.meaning;
    document.getElementById('slideReflection').textContent = name.reflection || 'Размышляйте над величием Аллаха и Его именем.';
    document.getElementById('slideApplication').textContent = name.application || 'Старайтесь применять это имя в своей жизни.';
    document.getElementById('slideDua').textContent = name.dua || 'سُبْحَانَ اللَّهِ';
    document.getElementById('nameCounter').textContent = `${index + 1} / ${fullNamesList.length}`;

    const isStudied = studiedNames.includes(index);
    const studyBtn = document.getElementById('studyBtn');
    if (isStudied) {
        studyBtn.textContent = '✅ Изучено';
        studyBtn.classList.add('studied');
    } else {
        studyBtn.textContent = '📖 Отметить как изученное';
        studyBtn.classList.remove('studied');
    }

    updateProgress();
}

function showPrevName() {
    if (currentNameIndex > 0) {
        currentNameIndex--;
        loadName(currentNameIndex);
    }
}

function showNextName() {
    if (currentNameIndex < fullNamesList.length - 1) {
        currentNameIndex++;
        loadName(currentNameIndex);
    }
}

function toggleNameStudied() {
    const index = currentNameIndex;
    const idx = studiedNames.indexOf(index);
    if (idx > -1) {
        studiedNames.splice(idx, 1);
    } else {
        studiedNames.push(index);
    }
    localStorage.setItem('studiedNames', JSON.stringify(studiedNames));
    loadName(currentNameIndex);
    checkCertificate();
}

function updateProgress() {
    const total = fullNamesList.length;
    const studied = studiedNames.length;
    document.getElementById('progressText').textContent = `${studied} / ${total}`;
    document.getElementById('progressFill').style.width = `${(studied / total) * 100}%`;
    document.getElementById('studiedCount').textContent = studied;
    document.getElementById('remainingCount').textContent = total - studied;

    if (studied === total) {
        document.getElementById('certificateStatus').innerHTML = '🎉 <strong>ПОЛУЧЕН!</strong>';
        document.getElementById('certificateContainer').classList.add('show');
    } else {
        document.getElementById('certificateStatus').innerHTML = '🔒 Не получен';
        document.getElementById('certificateContainer').classList.remove('show');
    }
}

function checkCertificate() {
    const total = fullNamesList.length;
    const studied = studiedNames.length;
    if (studied === total) {
        document.getElementById('certificateStatus').innerHTML = '🎉 <strong>ПОЛУЧЕН!</strong>';
        document.getElementById('certificateContainer').classList.add('show');
        const today = new Date();
        document.getElementById('certDate').textContent = today.toLocaleDateString('ru-RU');
    } else {
        document.getElementById('certificateStatus').innerHTML = '🔒 Не получен';
        document.getElementById('certificateContainer').classList.remove('show');
    }
}

function resetAllNames() {
    if (confirm('Вы уверены, что хотите сбросить весь прогресс изучения имён?')) {
        studiedNames = [];
        localStorage.setItem('studiedNames', JSON.stringify(studiedNames));
        loadName(currentNameIndex);
        checkCertificate();
    }
}

function downloadCertificate() {
    const btn = document.querySelector('.download-cert-btn');
    btn.textContent = '⏳ Генерация...';
    setTimeout(() => {
        btn.textContent = '⬇️ Скачать сертификат';
        alert('Сделайте скриншот сертификата!');
    }, 1500);
}

function shareCertificate() {
    if (navigator.share) {
        navigator.share({
            title: '🌟 Сертификат — 99 имён Аллаха',
            text: 'Я изучил(а) 99 имён Аллаха!',
            url: window.location.href
        });
    } else {
        alert('Поделитесь своим достижением в соцсетях! 📱');
    }
}

// ============================================
// 10. ФУНКЦИИ ВИКТОРИНЫ
// ============================================
let currentQuestions = [];
let currentQuestionIndex = 0;
let score = 0;
let wrong = 0;
let isAnswered = false;
let selectedCount = 10;
let selectedDifficulty = 'easy';

function setQuestionCount(count) {
    selectedCount = count;
    document.querySelectorAll('.count-btn').forEach(btn => {
        btn.classList.toggle('active', parseInt(btn.dataset.count) === count);
    });
}

function setDifficulty(difficulty) {
    selectedDifficulty = difficulty;
    document.querySelectorAll('.diff-btn').forEach(btn => {
        btn.classList.toggle('active', btn.dataset.diff === difficulty);
    });
}

function getDifficultyLabel(difficulty) {
    const labels = { 'easy': '🌱 Лёгкий', 'medium': '📖 Средний', 'hard': '🏛️ Сложный' };
    return labels[difficulty] || difficulty;
}

function getDifficultyEmoji(difficulty) {
    const emojis = { 'easy': '🌱', 'medium': '📖', 'hard': '🏛️' };
    return emojis[difficulty] || '⭐';
}

function startQuiz() {
    let filtered = allQuestions.filter(q => q.difficulty === selectedDifficulty);
    if (filtered.length < selectedCount) {
        filtered = allQuestions.filter(q => q.difficulty === selectedDifficulty);
    }
    const shuffled = filtered.sort(() => Math.random() - 0.5);
    currentQuestions = shuffled.slice(0, Math.min(selectedCount, shuffled.length));
    if (currentQuestions.length === 0) {
        alert('Извините, для выбранной сложности нет вопросов. Попробуйте другую сложность.');
        return;
    }
    currentQuestionIndex = 0;
    score = 0;
    wrong = 0;
    isAnswered = false;
    document.getElementById('quizSettings').style.display = 'none';
    document.getElementById('quizGame').style.display = 'block';
    document.getElementById('resultsContainer').style.display = 'none';
    document.getElementById('quizDifficultyDisplay').textContent = getDifficultyLabel(selectedDifficulty);
    loadQuestion();
}

function exitQuiz() {
    if (confirm('Вы уверены, что хотите выйти из викторины? Прогресс будет потерян.')) {
        document.getElementById('quizGame').style.display = 'none';
        document.getElementById('resultsContainer').style.display = 'none';
        document.getElementById('quizSettings').style.display = 'block';
    }
}

function loadQuestion() {
    const question = currentQuestions[currentQuestionIndex];
    const total = currentQuestions.length;
    document.getElementById('questionNumber').textContent = `Вопрос ${currentQuestionIndex + 1} из ${total}`;
    document.getElementById('questionText').textContent = question.question;
    document.getElementById('quizProgress').textContent = `${currentQuestionIndex + 1}/${total}`;
    document.getElementById('quizScore').textContent = score;
    document.getElementById('quizWrong').textContent = wrong;

    const progress = ((currentQuestionIndex) / total) * 100;
    const circle = document.getElementById('progressCircle');
    const circumference = 219.9;
    const offset = circumference - (progress / 100) * circumference;
    circle.style.strokeDashoffset = offset;
    document.getElementById('progressText').textContent = `${Math.round(progress)}%`;

    const optionsContainer = document.getElementById('optionsContainer');
    const feedbackContainer = document.getElementById('feedbackContainer');
    const nextBtn = document.getElementById('nextBtn');

    optionsContainer.innerHTML = '';
    feedbackContainer.classList.remove('show', 'correct', 'wrong');
    feedbackContainer.querySelector('#feedbackText').textContent = '';

    const letters = ['А', 'Б', 'В', 'Г'];
    question.options.forEach((option, index) => {
        const optionDiv = document.createElement('div');
        optionDiv.className = 'quiz-option';
        optionDiv.innerHTML = `<span class="option-letter">${letters[index]}.</span><span>${option}</span>`;
        optionDiv.dataset.index = index;
        optionDiv.onclick = function() { selectAnswer(index); };
        optionsContainer.appendChild(optionDiv);
    });

    isAnswered = false;
    nextBtn.disabled = true;
}

function selectAnswer(selectedIndex) {
    if (isAnswered) return;
    isAnswered = true;
    const question = currentQuestions[currentQuestionIndex];
    const options = document.querySelectorAll('.quiz-option');
    const feedbackContainer = document.getElementById('feedbackContainer');
    const feedbackText = document.getElementById('feedbackText');
    const nextBtn = document.getElementById('nextBtn');

    options.forEach(opt => opt.classList.add('disabled'));
    options.forEach((opt, index) => {
        if (index === question.correct) opt.classList.add('correct');
        if (index === selectedIndex && selectedIndex !== question.correct) opt.classList.add('wrong');
    });

    if (selectedIndex === question.correct) {
        score++;
        feedbackContainer.className = 'quiz-feedback show correct';
        feedbackText.innerHTML = `✅ <strong>Правильно!</strong> ${question.explanation}`;
    } else {
        wrong++;
        const correctText = question.options[question.correct];
        feedbackContainer.className = 'quiz-feedback show wrong';
        feedbackText.innerHTML = `❌ <strong>Неправильно.</strong> Правильный ответ: <strong>${correctText}</strong><br><span class="feedback-explanation">${question.explanation}</span>`;
    }
    document.getElementById('quizScore').textContent = score;
    document.getElementById('quizWrong').textContent = wrong;
    nextBtn.disabled = false;
}

function nextQuestion() {
    currentQuestionIndex++;
    if (currentQuestionIndex < currentQuestions.length) {
        loadQuestion();
    } else {
        showResults();
    }
}

function showResults() {
    document.getElementById('quizContainer').style.display = 'none';
    document.getElementById('resultsContainer').style.display = 'block';
    const total = currentQuestions.length;
    document.getElementById('finalCorrect').textContent = score;
    document.getElementById('finalWrong').textContent = wrong;
    document.getElementById('finalTotal').textContent = total;
    document.getElementById('finalDifficulty').textContent = getDifficultyEmoji(selectedDifficulty);

    const percent = Math.round((score / total) * 100);
    const messageEl = document.getElementById('resultMessage');
    const emojiEl = document.getElementById('resultEmoji');
    const titleEl = document.getElementById('resultTitle');

    if (percent === 100) {
        emojiEl.textContent = '🏆';
        titleEl.textContent = 'Совершенство!';
        messageEl.innerHTML = '🌟 <strong>Превосходно!</strong> Вы ответили на все вопросы правильно!';
        messageEl.style.color = '#2ecc71';
    } else if (percent >= 80) {
        emojiEl.textContent = '⭐';
        titleEl.textContent = 'Отличный результат!';
        messageEl.innerHTML = '📚 <strong>Отлично!</strong> У вас хорошие знания.';
        messageEl.style.color = '#c9a84c';
    } else if (percent >= 60) {
        emojiEl.textContent = '🌟';
        titleEl.textContent = 'Хороший результат!';
        messageEl.innerHTML = '📖 <strong>Хорошо!</strong> Вы знаете основы.';
        messageEl.style.color = '#f39c12';
    } else if (percent >= 40) {
        emojiEl.textContent = '📖';
        titleEl.textContent = 'Средний результат';
        messageEl.innerHTML = '📕 <strong>Средний результат.</strong> Рекомендуем начать с изучения основ.';
        messageEl.style.color = '#e67e22';
    } else {
        emojiEl.textContent = '📗';
        titleEl.textContent = 'Начните с основ';
        messageEl.innerHTML = '📗 <strong>Начните с основ.</strong> Изучайте столпы Ислама.';
        messageEl.style.color = '#e74c3c';
    }
}

function restartQuiz() {
    document.getElementById('resultsContainer').style.display = 'none';
    document.getElementById('quizGame').style.display = 'none';
    document.getElementById('quizSettings').style.display = 'block';
}

