function renderTajweed() {
    const grid = document.getElementById('tajweedGrid');
    if (!grid) return;
    grid.innerHTML = '';
    tajweedData.forEach((rule, index) => {
        const card = document.createElement('div');
        card.className = 'rule-card';
        card.innerHTML = `
            <button class="expand-btn" onclick="openFullscreen(${index})" title="Развернуть">⛶</button>
            <div class="rule-symbol">${rule.symbol}</div>
            <h3>${rule.name}</h3>
            <p class="rule-desc">${rule.description}</p>
            <div class="example-block">
                <div class="example-arabic">${rule.example_arabic}</div>
                <div class="example-russian">📢 ${rule.example_russian}</div>
            </div>
        `;
        grid.appendChild(card);
    });
}

