// ============================================
// 12. ПОЛНОЭКРАННЫЙ РЕЖИМ
// ============================================
function openFullscreen(index) {
    const modal = document.getElementById('fullscreenModal');
    const modalBody = document.getElementById('modalBody');
    const rule = tajweedData[index];
    if (!rule) return;
    modalBody.innerHTML = `
        <div class="modal-rule-symbol">${rule.symbol}</div>
        <h2 class="modal-rule-name">${rule.name}</h2>
        <div class="modal-rule-desc">${rule.description}</div>
        <div class="modal-example-block">
            <div class="modal-example-arabic">${rule.example_arabic}</div>
            <div class="modal-example-russian">📢 ${rule.example_russian}</div>
        </div>
        <div class="modal-detail">
            <h4>📖 Подробное объяснение:</h4>
            <p>${rule.detail || 'Нажмите на правило, чтобы увидеть подробное объяснение.'}</p>
        </div>
    `;
    modal.classList.add('active');
    document.body.style.overflow = 'hidden';
}

function closeFullscreen() {
    const modal = document.getElementById('fullscreenModal');
    modal.classList.remove('active');
    document.body.style.overflow = 'auto';
}

document.addEventListener('keydown', function(e) {
    if (e.key === 'Escape') closeFullscreen();
    if (e.key === 'ArrowRight' && document.getElementById('tab-names').classList.contains('active')) showNextName();
    if (e.key === 'ArrowLeft' && document.getElementById('tab-names').classList.contains('active')) showPrevName();
});

// ============================================
// 13. ПЕРЕКЛЮЧЕНИЕ ВКЛАДОК
// ============================================
function showTab(tabId) {
    const tabs = document.querySelectorAll('.tab-content');
    tabs.forEach(tab => tab.classList.remove('active'));
    const buttons = document.querySelectorAll('nav button');
    buttons.forEach(btn => btn.classList.remove('active'));
    const target = document.getElementById(`tab-${tabId}`);
    if (target) target.classList.add('active');
    const activeButton = document.querySelector(`nav button[onclick="showTab('${tabId}')"]`);
    if (activeButton) activeButton.classList.add('active');
}

// ============================================
// 14. НАСТРОЙКИ
// ============================================
document.addEventListener('DOMContentLoaded', function() {
    renderTajweed();
    renderWaqf();
    renderAlphabet();
    renderNumbers();
    renderDua();

    if (fullNamesList.length > 0) {
        loadName(0);
    }

    const fontSizeSlider = document.getElementById('fontSize');
    const fontSizeLabel = document.getElementById('fontSizeLabel');

    if (fontSizeSlider) {
        fontSizeSlider.addEventListener('input', function() {
            const size = this.value + 'px';
            fontSizeLabel.textContent = this.value + 'px';
            document.querySelectorAll('.example-arabic, .modal-example-arabic, .letter-arabic, .name-arabic-big, .dua-arabic, .number-arabic')
                .forEach(el => el.style.fontSize = size);
        });
    }

    if (localStorage.getItem('theme') === 'dark') {
        document.body.classList.add('dark-theme');
        const btn = document.getElementById('themeBtn');
        if (btn) btn.textContent = '☀️ Дневной режим';
    }

    const themeBtn = document.getElementById('themeBtn');
    if (themeBtn) {
        themeBtn.onclick = function() {
            document.body.classList.toggle('dark-theme');
            const isDark = document.body.classList.contains('dark-theme');
            this.textContent = isDark ? '☀️ Дневной режим' : '🌙 Ночной режим';
            localStorage.setItem('theme', isDark ? 'dark' : 'light');
        };
    }

    const savedFontSize = localStorage.getItem('fontSize');
    if (savedFontSize) {
        const slider = document.getElementById('fontSize');
        const label = document.getElementById('fontSizeLabel');
        if (slider && label) {
            slider.value = savedFontSize;
            label.textContent = savedFontSize + 'px';
            document.querySelectorAll('.example-arabic, .modal-example-arabic, .letter-arabic, .name-arabic-big, .dua-arabic, .number-arabic')
                .forEach(el => el.style.fontSize = savedFontSize + 'px');
        }
    }

    if (fontSizeSlider) {
        fontSizeSlider.addEventListener('change', function() {
            localStorage.setItem('fontSize', this.value);
        });
    }
});

